"""
SVG icon helpers for Dash 4.1.0.
Encodes SVG as base64 data URI and renders via html.Img.
This is the only reliable cross-browser approach in this Dash version.
"""
import base64
from dash import html


def _svg_img(svg_str: str, size: int = 20, style: dict = None) -> html.Img:
    b64 = base64.b64encode(svg_str.encode()).decode()
    s = {"display": "inline-block", "verticalAlign": "middle", "lineHeight": "1"}
    if style:
        s.update(style)
    return html.Img(
        src=f"data:image/svg+xml;base64,{b64}",
        width=size, height=size,
        style=s,
    )


# ── Icon factory ───────────────────────────────────────────────────────────
def ico_credit_card(color="#FF6584", size=20):
    return _svg_img(f'<svg xmlns="http://www.w3.org/2000/svg" width="{size}" height="{size}" viewBox="0 0 24 24" fill="none" stroke="{color}" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><rect x="1" y="4" width="22" height="16" rx="2"/><line x1="1" y1="10" x2="23" y2="10"/></svg>', size)

